import java.util.*

class SessionTokenGenerator {
    private val charset = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789".toCharArray()

    fun generateSessionId(): String {
        val random = Random()
        return (1..32).map { charset[random.nextInt(charset.size)] }.joinToString("")
    }
